var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"다행히 건물이 무너지던 와중에도 이곳은 무사하군.","JPN":"建物は崩壊しているが、幸いここだけは無事のようだ。","ENG":"Luckily, this place seems safe given the building is crumbling.","TWN":"幸好建築物雖然倒塌，但這裡沒有遭殃。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"갑자기 뛰어가시면 어떡해요?! 그러다가 건물이 또 무너지면 어떡하시려고!","JPN":"急に走り出してどうしたんですか！？　また建物が崩れたりしたら大変なんですよ！","ENG":"Where are you suddenly running off to?! What if the building starts to come down again?!","TWN":"你怎麼可以突然跑走？！萬一建築物又倒塌的話怎麼辦！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"은폐장은 물론이고, 모든 보안 장치가 파괴되었어.","JPN":"隠蔽バリアをはじめとする、あらゆるセキュリティ装置が破損している。","ENG":"The cloaking barrier and all security devices have been destroyed.","TWN":"不只是藏身之處，連所有的安全設備也都遭到破壞。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"정말…… 이렇게 많은 시간이 흘렀다고?","JPN":"本当に……それだけの時間が流れたというのか？","ENG":"Has... it really been that long?","TWN":"我真的……有沉睡這麼長的時間嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이렇게 모든 배관이 캡슐을 향해 이어져 있었어요.","JPN":"ここにあるすべてのパイプがカプセルに繋がっていました。","ENG":"All the pipes were connected to the capsule like this.","TWN":"所有的管線都通向膠囊，"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그 배관을 따라갔더니 당신이 잠들어 있었죠.","JPN":"パイプを辿っていくと、そこにはあなたが眠っていたんです。","ENG":"I was following them when I found you asleep.","TWN":"我沿著那些管線走，就看見你在沉睡。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"떠오르는 게 있으신가요?","JPN":"何か思い出しましたか？","ENG":"Is there anything that you do remember?","TWN":"你有想起什麼嗎？ "},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"전혀. 내가 착각하고 있는 것은 아닐지 걱정될 정도로.","JPN":"まったくだ。私が錯覚しているのではないかと心配になるくらいにな。","ENG":"Nothing. Enough so that I'm worried I might be mistaken.","TWN":"完全沒有，我甚至擔心是不是自己搞錯什麼。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"아니, 차라리 그랬으면 좋겠군.","JPN":"むしろ、その方がいいのかもしれないが。","ENG":"No, it would be better if I was.","TWN":"不，應該說，我寧願是我哪裡搞錯。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"내가 아주 잘 만들어진 복제 인간이라서 원본과 나를 혼동한다는 착각.","JPN":"私は精巧に作られた複製人間であり、本体と自分の区別がつかなくなっている……とか。","ENG":"Thinking that I'm a well-made clone who is getting confused with the original.","TWN":"我希望我其實是一個完美複製人，所以才會把我和本尊搞錯。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"그 나침반을 잠깐 봐도 되겠나?","JPN":"その羅針盤を見せてもらえるか？","ENG":"That compass, may I see it?","TWN":"那個指南針可以借我看一下嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"여기요.","JPN":"はい、どうぞ。","ENG":"Here you go.","TWN":"給你。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"…… 내가 움직이는 방향을 따라오는군.","JPN":"……針が私を追ってくる。","ENG":"...It's following the direction I'm moving to.","TWN":"…… 針跟著我移動呢。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"여러 곳을 떠돌아다니면서도 이상하게도 잃어버리지 않았던 물건이에요.","JPN":"色んな場所を放浪してきましたが、これだけは決して無くしませんでした。","ENG":"Strangely enough, this is the one thing that I haven't lost while wandering around everywhere.","TWN":"而且很奇怪，我去過這麼多地方，卻從來沒有弄丟過它。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"언제부터 가지고 있었는지도 잘 모르겠어요. 하지만 항상 제 곁에 있었죠.","JPN":"いつからあったのかもわかりませんが、常に私の手元にあったんです。","ENG":"I'm not sure how long I've had it. But it's been with me ever since.","TWN":"也記不清是從什麼時候開始帶在身上的，總之它就是跟我形影不離。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"바늘이 당신을 향한다는 건 여기 와서 안 사실이지만…….","JPN":"針が示していたのがあなただったとは、ここに来て知りましたが……","ENG":"I only learned that it points to you after coming here, however...","TWN":"不過針指向你，是我到這裡後才發現的……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"나를 향하는 나침반이라…….","JPN":"私を示す羅針盤か……","ENG":"A compass that points to me...","TWN":"指向我的指南針……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"이건 여러분들 모두에게 지급되는 장비인 나침반입니다.","JPN":"この羅針盤は、皆さん一人一人に支給されます。","ENG":"This is a compass that will be issued to all of you.","TWN":"這是指南針，是要會發給各位的裝備。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"바늘은 같은 나침반을 향해 움직이죠.","JPN":"針は同じ羅針盤同士を指し示します。","ENG":"The needle inside will point toward another compass.","TWN":"上面的針會朝著相同的指南針移動。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"이 나침반은 서로의 위치를 더 잘 알게 하기 위함으로…….","JPN":"この羅針盤はお互いの位置を把握するのに役立ち……","ENG":"This equipment will be used to better know each other's locations...","TWN":"這個指南針用意在清楚彼此的位置……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"……나침반.","JPN":"……羅針盤。","ENG":"...The compass.","TWN":"……指南針。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"역시…… 나도 갖고 있었나.","JPN":"やはり……私も持っていたか。","ENG":"Do I... also have one?","TWN":"我……也有嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"앗…… 그건 제가 갖고 있는 나침반이랑 똑같은 거잖아요?","JPN":"あっ、それ！　私の羅針盤とそっくりです！","ENG":"Oh...? That's the same compass as the one I have.","TWN":"喔……這和我的指南針是一樣的？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그, 그럼 이 나침반은 당신이 갖고 있는 나침반을 따라서 움직이고 있었던 거였네요.","JPN":"じゃ、じゃあ、羅針盤の針が示していたのは、同じ羅針盤の位置だったんですね。","ENG":"Th-then, it wasn't pointing at you but following your compass.","TWN":"所以我的指南針是跟著你的指南針移動嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"우연이라기엔 너무나 절묘한 인연이야.","JPN":"ただの偶然にしては、何らかの繋がりを感じる。","ENG":"This encounter can't be just a coincidence.","TWN":"要說是湊巧未免也太剛好。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"아무래도 나침반이 널 나에게로 인도해 준 모양이군.","JPN":"どうやらこの羅針盤は、君を私のところに導いてくれたようだ。","ENG":"It seems that this compass has led you to me.","TWN":"我想是指南針帶你來找我的吧。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"네. 아직은 추측의 단계이지만 아버지와도 관계가 있지 않을까 싶어요.","JPN":"はい、まだ確証はありませんが、お父さんとも関係しているんじゃないかって思うんです。","ENG":"Yes. I'm still assuming, but I was wondering if it also has anything to do with my father.","TWN":"沒錯，雖然只是猜測，但我想你或許和我爸爸有什麼關係也說不定。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그래도 사막에서 쓰러져 죽거나, 팔려 가기 전에 뭐라도 찾아서 다행이네요.","JPN":"とにかく、砂漠のど真ん中で死んじゃったり、売り飛ばされる前に、何かしら見つけることができてよかったです。","ENG":"I'm relieved that I found something before I got sold as a slave or died in the desert.","TWN":"幸好在我死在沙漠，或是被人口販子賣掉前有找到一點線索。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그냥 나침반이 움직이는 대로 여기저기 떠돌아다녔거든요. 헤헤.","JPN":"ひたすら、羅針盤が指し示すままに、あちこち歩き回っていたので。","ENG":"I was just following the compass blindly wherever it took me. Hehe.","TWN":"因為我也只是照著指南針移動的方向到處走，嘿嘿。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"대책 없는 건지, 긍정적인 건지…….","JPN":"無謀と言うべきか、行動力があると言うべきか……","ENG":"I can't tell if you're shortsighted or someone with a positive outlook...","TWN":"該說你有勇無謀還是天生樂觀呢……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"나침반이 나와 관련되었다고 판단한 이상, 너와 협력하겠다.","JPN":"羅針盤が私と関係しているとわかった以上、君に協力しよう。","ENG":"Since I have determined that this compass has something to do with me, I will cooperate.","TWN":"既然指南針與我有關，那我會協助你。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"우리 모두 잃어버린 걸 찾고 있으니 서로 좋은 파트너가 될 수 있을 것 같군.","JPN":"お互い失ったものを探している者同士、良いパートナーになりそうだ。","ENG":"I believe we will make good partners finding what each of us has lost.","TWN":"我們都在尋找失去的東西，應該可以成為好夥伴。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이렇게 쉽게 풀릴 줄 알았으면 진작 나침반부터 보여드릴 걸 그랬네요.","JPN":"こんなに早く話が進むなら、さっさと羅針盤を見せればよかったです。","ENG":"If I had known it would be this easy, I would've shown you the compass from the start.","TWN":"早知道你會這麼爽快答應，我應該早點拿出指南針。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그러니까…… 이제부턴 뭐라고 부르면 되나요?","JPN":"それで……これからは何と呼べばいいんでしょうか？","ENG":"So... what should I call you?","TWN":"不過……我該怎麼稱呼你才好？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"카운터님? 절정 고수? 구원자? 차크람 우먼? 파트너?","JPN":"カウンター様？　凄腕達人様？　救世主？　チャクラム女？　パートナー？","ENG":"Miss Counter? Expert? Savior? Chakram woman? Partner?","TWN":"制裁者小姐？女俠？救命恩人？神力女超人？夥伴？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"촌스러운 네이밍.","JPN":"どれもこれもセンスがないな。　","ENG":"Such tacky names.","TWN":"都不好。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"너, 그리고 나침반을 봤을 때 어떤 장면이 떠올랐다.","JPN":"君とその羅針盤を見た瞬間、ふと思い出した記憶がある。","ENG":"When I saw you and the compass, I recalled a certain scene.","TWN":"當我看你和指南針時，腦中有閃過一些畫面。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"내 사라진 기억과 관련이 있는 것들이라 추측할 뿐, 무엇인지는 알 수 없었지.","JPN":"私の消えた記憶と関係しているだろうと推測はできるが、それが何なのかまでは分からなかった。","ENG":"I can only guess that it's related to my lost memories, but I can't figure out what.","TWN":"是和我消失的記憶有關的，但這只是猜測，無法確認到底是什麼。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"하지만 동시에…… 계속해서 환청이 들리고 있어.","JPN":"しかし、それと同時に……幻聴が始まった。","ENG":"But at the same time... I keep having auditory hallucinations.","TWN":"同時……我會一直產生幻聽。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"총소리와 침식체, 그리고 기억나지 않는 사람들.","JPN":"銃声や侵食体、そして思い出せない人物たち。","ENG":"Gunshots and C.O.s... and people I don't remember.","TWN":"會聽到槍聲、侵蝕體，還有想不起來的人。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"그들은 계속해서 날 부르고 있어. 지금도.","JPN":"彼らが私を呼んでいる、今もだ。","ENG":"They keep calling me. Even now.","TWN":"他們會一直叫我，就連現在也是。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……환청을 듣고 계신다고요?","JPN":"……幻聴が聞こえるんですか？","ENG":"...You're hearing things?","TWN":"……你有幻聽喔？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"그래. 마치 나를 아주 잘 안다는 듯이. 나를 이렇게 부르더군.","JPN":"ああ。あたかも言い慣れた呼び方であるように、私をこう呼んでいる。","ENG":"Yes. They call me as if they know me very well.","TWN":"對，他們彷彿跟我很熟似的，會這樣叫我。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L37_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"■■■ ■■■■■ ■■■ 아디트야.","JPN":"■■■ ■■■■■ ■■■アーディティヤ。","ENG":"■■■ ■■■■■ ■■■, Aditya.","TWN":"■■■ ■■■■■ ■■■，阿迪亞。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"<color=#ffd34c>아디트야. </color>","JPN":"<color=#ffd34c>アーディティヤ。</color>","ENG":"<color=#ffd34c>Aditya.</color>","TWN":"<color=#ffd34c>阿迪亞。</color>"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나를 아디트야라고 불러라.","JPN":"私をアーディティヤと呼ぶといい。","ENG":"Call me, Aditya.","TWN":"叫我阿迪亞。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};